const { Logger: MeliLogger } = require('@meli/logger');

const methods = ['info', 'warn', 'error', 'debug'];
const traceMethods = ['verbose', 'silly'];

function Logger(name, options = {}) {
  this.name = name;
  this.options = options;
  this.client = new MeliLogger(name);

  return this;
}

methods.forEach((method) => {
  // eslint-disable-next-line func-names
  Logger.prototype[method] = function (msg, tags) {
    this.client[method](msg, tags);
  };
});

traceMethods.forEach((method) => {
  // eslint-disable-next-line func-names
  Logger.prototype[method] = function (msg, tags) {
    this.client.trace(msg, tags);
  };
});

module.exports = Logger;
